parameters.jsCode:
const job = $input.first().json;
const result = job.result ?? {};

const steps = Array.isArray(result.steps)
  ? result.steps
  : [];

return [
  {
    json: {
      jobId: job.jobId,
      jobStatus: job.status,

      processId: job.processId,
      processName: job.processName,

      executionStatus: result.status ?? null,
      durationMs: result.durationMs ?? null,

      stepsExecuted: steps.length,

      completedSteps: steps.filter(
        step => step.status === 'COMPLETED'
      ).length,

      warningSteps: steps.filter(
        step => step.status === 'IGNORED_ERROR'
      ).length,

      failedSteps: steps.filter(
        step => step.status === 'FAILED'
      ).length,

      failedStepId: result.failedStepId ?? null,

      errorMessage:
        result.errorMessage ??
        job.errorMessage ??
        null,

      steps
    }
  }
];

parameters.errorMessage:
={{
  'Falló el proceso '
  + ($json.processName ?? 'desconocido')
  + ' en el paso '
  + ($json.failedStepId ?? 'desconocido')
  + ': '
  + ($json.errorMessage ?? 'Sin detalle del error')
}}
